using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Good case: Retrieve an existing EHR record/// Expected: 200 OK with EHR record data/// </summary>public class EhrServiceTests_GetEhrRecord_WithValidId_ShouldReturnRecord : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task GetEhrRecord_WithValidId_ShouldReturnRecord()    {        await AuthenticateAsDoctorAsync(EhrClient);        // Step 1: Create an EHR record        var createRequest = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Test diagnosis",                 treatment = "Test treatment",                 notes = "Test notes"             }         };        var createResponse = await PostAsJsonWithRetryAsync(EhrClient, ApiEndpoints.Ehr.CreateRecord, createRequest);        var createJson = await ReadJsonResponseAsync(createResponse);                if (!createJson.TryGetProperty("ehrId", out var ehrIdElement))            return; // Skip if creation fails        var ehrId = Guid.Parse(ehrIdElement.GetString()!);        // Step 2: Retrieve the created record        var getResponse = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.GetRecord(ehrId));        Assert.Equal(HttpStatusCode.OK, getResponse.StatusCode);                var getJson = await ReadJsonResponseAsync(getResponse);        Assert.True(getJson.TryGetProperty("ehrId", out var retrievedEhrId));        Assert.Equal(ehrId.ToString(), retrievedEhrId.GetString());    }}
